class FastPrefix:
    def __init__(self, n):
        self.n = n
        self.bit = [0] * (n + 1)
    def add(self, i, delta):
        n = self.n
        while i <= n:
            self.bit[i] = (self.bit[i] + delta) % MOD
            i += i & -i
    def sum(self, i):
        res = 0
        while i > 0:
            res = (res + self.bit[i]) % MOD
            i -= i & -i
        return res
    def range_sum(self, l, r):
        return (self.sum(r) - self.sum(l - 1)) % MOD

